import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;

public class Reproduction {
    public static void main(String[] args) {
        String dirty = "<html><head><script></script><noscript></noscript></head><frameset><frame src=\"foo\" /><frame src=\"foo\" /></frameset></html>";
        Document dirtyDoc = Jsoup.parse(dirty);
        Element body = dirtyDoc.body();
        if (body == null) {
            System.out.println("dirtyDoc.body() is NULL");
        } else {
            System.out.println("dirtyDoc.body() is NOT NULL: " + body.outerHtml());
        }
    }
}

import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;

public class ReproductionParseBody {
    public static void main(String[] args) {
        String dirty = "<html><head><script></script><noscript></noscript></head><frameset><frame src=\"foo\" /><frame src=\"foo\" /></frameset></html>";
        Document doc = Jsoup.parseBodyFragment(dirty);
        System.out.println("Parsed Body Fragment:");
        System.out.println(doc.outerHtml());
        System.out.println("Body exists? " + (doc.body() != null));
        if (doc.body() != null) {
            System.out.println("Body children: " + doc.body().children().size());
            for (Element child : doc.body().children()) {
                System.out.println(" - " + child.tagName());
            }
        }
    }
}
